module RefModule(in, enable, clear, clk, out);input [5:0] in;
  input enable;
  input clear;
  input clk;
  output [5:0] out;

  reg [5:0] states;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or posedge dbg_halt) begin
    if(enable && clear) begin
      states = 6'b000000;
    end

    else if(enable) begin
      states <= in;
    end
  end

  assign out = states;

endmodule
